step3-save-after-add.starterCode:
tasks = []

while True:
    print("Task Tracker")
    print("1. Add task")
    print("2. Show tasks")
    print("3. Quit")

    choice = input()

    if choice == "1":
        task = input()
        tasks.append(task)
        print("Task added")
    elif choice == "2":
        if len(tasks) == 0:
            print("No tasks yet")
        else:
            for index, task in enumerate(tasks, start=1):
                print(f"{index}. {task}")
    elif choice == "3":
        print("Goodbye!")
        break
    else:
        print("Invalid choice")
